import { useState, useEffect, useRef, useCallback } from 'react';
import { useRegisterSW } from 'virtual:pwa-register/react';
import { ArrowsClockwise, X } from '@phosphor-icons/react';

/**
 * PWA ?낅뜲?댄듃 愿由?n * 
 * - ?ㅼ삤?ㅽ겕(/checkin): SW controller 援먯껜 媛먯? ??30珥??좏쑕 ?湲????먮룞 ?덈줈怨좎묠
 * - 愿由ъ옄/?뚯썝: ?낅뜲?댄듃 諛곕꼫 ?쒖떆 (?섎룞 ?대┃)
 */
const IDLE_TIMEOUT_MS = 30_000;

function ReloadPrompt() {
  const [updating, setUpdating] = useState(false);
  const lastActivityRef = useRef(Date.now());
  const pendingReloadRef = useRef(false);
  const idleTimerRef = useRef(null);

  const {
    needRefresh: [needRefresh, setNeedRefresh],
    updateServiceWorker,
  } = useRegisterSW({
    onRegistered(r) {
      console.log('[SW] Registered');
      if (r) {
        r.update().catch(() => {});
        setInterval(() => { r.update(); }, 60 * 60 * 1000);
      }
    },
    onRegisterError(error) {
      console.log('[SW] registration error', error);
    },
  });

  // ?곣봺?곣봺 ?좏쑕 媛먯? ?곣봺?곣봺
  const markActivity = useCallback(() => {
    lastActivityRef.current = Date.now();
  }, []);

  useEffect(() => {
    const events = ['touchstart', 'mousedown', 'keydown', 'scroll'];
    events.forEach(evt => window.addEventListener(evt, markActivity, { passive: true }));
    return () => events.forEach(evt => window.removeEventListener(evt, markActivity));
  }, [markActivity]);

  // ?곣봺?곣봺 ?ㅼ삤?ㅽ겕 ?먮룞 ?덈줈怨좎묠: controllerchange ?대깽???ъ슜 ?곣봺?곣봺
  // ??긽 耳쒕넃??臾댁씤 ?? ?ㅼ삤?ㅽ겕留????좏쑕 ???먮룞 ?덈줈怨좎묠
  // [FIX] 愿由ъ옄?깆? ?먯옣??蹂닿퀬 ?덉쑝誘濡??먮룞 由щ줈?쒗븯硫?源쒕컯????諛곕꼫濡??덈궡
  const isAlwaysOn = typeof window !== 'undefined' && (
    window.location.pathname.startsWith('/checkin')
  );

  const startIdleReloadLoop = useCallback(() => {
    if (idleTimerRef.current) return; // ?대? 媛먯떆 以?n    pendingReloadRef.current = true;
    console.log('[SW] Update detected ??starting idle reload loop');

    idleTimerRef.current = setInterval(() => {
      if (!pendingReloadRef.current) {
        clearInterval(idleTimerRef.current);
        idleTimerRef.current = null;
        return;
      }
      const idleMs = Date.now() - lastActivityRef.current;
      if (idleMs >= IDLE_TIMEOUT_MS) {
        console.log(`[SW] Idle for ${Math.round(idleMs / 1000)}s ??auto-reloading`);
        pendingReloadRef.current = false;
        clearInterval(idleTimerRef.current);
        idleTimerRef.current = null;
        window.location.reload();
      }
    }, 5_000);
  }, []);

  useEffect(() => {
    if (!isAlwaysOn || !('serviceWorker' in navigator)) return;

    // [FIX] 以묎뎅 OS ?쒕툝由? 泥?濡쒕뱶 ??controller 援먯껜 ?대깽?멸? 利됱떆 諛쒖깮?섏뿬 由щ줈??猷⑦봽
    // ???섏씠吏 濡쒕뱶 ??60珥??대궡 controllerchange??臾댁떆
    const pageLoadedAt = Date.now();
    const GRACE_PERIOD_MS = 60_000;

    // autoUpdate 紐⑤뱶?먯꽌 ?ㅼ젣 SW 援먯껜 媛먯?
    const onControllerChange = () => {
      const elapsed = Date.now() - pageLoadedAt;
      if (elapsed < GRACE_PERIOD_MS) {
        console.log(`[SW] Controller changed within grace period (${Math.round(elapsed/1000)}s) ??ignoring`);
        return;
      }
      console.log('[SW] Controller changed ??new SW active');
      startIdleReloadLoop();
    };

    navigator.serviceWorker.addEventListener('controllerchange', onControllerChange);
    return () => {
      navigator.serviceWorker.removeEventListener('controllerchange', onControllerChange);
      if (idleTimerRef.current) clearInterval(idleTimerRef.current);
    };
  }, [isAlwaysOn, startIdleReloadLoop]);

  // needRefresh ?몃━嫄곕룄 fallback?쇰줈 ?좎?
  useEffect(() => {
    if (needRefresh && isAlwaysOn) {
      startIdleReloadLoop();
    }
  }, [needRefresh, isAlwaysOn, startIdleReloadLoop]);

  // ?곣봺?곣봺 ?섎룞 ?낅뜲?댄듃 (愿由ъ옄/?뚯썝 ?깆슜) ?곣봺?곣봺
  const handleUpdate = async () => {
    if (updating) return;
    setUpdating(true);
    console.log('[SW] Update button clicked');

    const fallbackTimer = setTimeout(() => {
      console.log('[SW] updateServiceWorker did not reload within 3s, forcing reload');
      window.location.reload();
    }, 3000);

    try {
      await updateServiceWorker(true);
    } catch (err) {
      console.warn('[SW] updateServiceWorker failed:', err);
      clearTimeout(fallbackTimer);
      window.location.reload();
    }
  };

  // ?ㅼ삤?ㅽ겕/愿由ъ옄: ?먮룞 泥섎━ ??諛곕꼫 ??蹂댁뿬以?n  if (!needRefresh || isAlwaysOn) {
    return null;
  }

  return (
    <div style={{
        position: 'fixed',
        bottom: '20px',
        right: '20px',
        background: 'var(--primary-gold)',
        border: '1px solid rgba(255,255,255,0.2)',
        borderRadius: '12px',
        boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
        padding: '16px 20px',
        display: 'flex',
        flexDirection: 'column',
        gap: '12px',
        zIndex: 9999,
        color: 'var(--text-on-primary)',
        fontFamily: 'var(--font-main)',
        animation: 'slideUp 0.3s ease-out'
    }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '20px' }}>
             <div style={{ fontWeight: 'bold', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                 <ArrowsClockwise size={20} weight="bold" className="spin-hover" />
                 ?덈줈??踰꾩쟾??以鍮꾨릺?덉뒿?덈떎
             </div>
             <button 
                onClick={() => setNeedRefresh(false)}
                style={{ background: 'none', border: 'none', color: 'var(--text-on-primary)', cursor: 'pointer', padding: 0, opacity: 0.6 }}
             >
                 <X size={20} weight="bold" />
             </button>
        </div>
        <div style={{ fontSize: '0.85rem', opacity: 0.8, fontWeight: '500' }}>
            ?덈줈??湲곕뒫 ?쒖꽦??諛?理쒖쟻?붾? ?꾪빐<br/>吏湲??낅뜲?댄듃瑜?吏꾪뻾?댁＜?몄슂.
        </div>
        <button
            onClick={handleUpdate}
            disabled={updating}
            style={{
                background: 'black', color: 'var(--primary-gold)',
                border: 'none', padding: '10px', borderRadius: '8px',
                fontWeight: 'bold', fontSize: '0.9rem', cursor: updating ? 'wait' : 'pointer',
                marginTop: '4px',
                opacity: updating ? 0.7 : 1
            }}
        >
            {updating ? '?낅뜲?댄듃 以?..' : '?대┃?섏뿬 ?낅뜲?댄듃 諛??ъ떆??}
        </button>
    </div>
  );
}

export default ReloadPrompt;

import { useState } from 'react';
import { Plus, X } from '@phosphor-icons/react';
import { storageService } from '../services/storage';
import { useStudioConfig } from '../contexts/StudioContext';

const ScheduleClassEditor = ({ cls, idx, dayClasses, setDayClasses, instructors, classTypes, classLevels }) => {
    const selectStyle = { 
        // fallback generic styles
        fontSize: '0.9rem', 
        padding: '8px 30px 8px 8px', // right padding 30px for the custom caret
        borderRadius: '8px',
        border: '1px solid var(--border-color)',
        backgroundColor: 'var(--bg-surface, #1e1e1e)',
