                    </div>

                    {/* ?섏뾽 醫낅쪟 愿由??뱀뀡 */}
                    <div style={sectionCardStyle}>
                        <div style={sectionHeaderStyle}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
