                                                }
                                            }
                                        }}
                                        style={deleteIconBtnStyle}
                                    >
                                        <X size={14} weight="bold" />
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
