    const tabs = [
        { id: 'members', label: '?뚯썝 ?묒? (?띿뒪??', type: 'text' },
        { id: 'timetable', label: '?쒓컙??(?대?吏)', type: 'image' },
        { id: 'pricing', label: '媛寃⑺몴 (?대?吏)', type: 'image' }
    ];

    const currentTabInfo = tabs.find(t => t.id === activeTab);

    const handleFileChange = (e) => {
        const selectedFile = e.target.files[0];
        if (selectedFile) processFile(selectedFile);
    };

    const processFile = (selectedFile) => {
        setError(null);
        setParsedData(null);

        if (currentTabInfo.type === 'image' && !selectedFile.type.startsWith('image/')) {
            setError('?대?吏 ?뚯씪(JPG, PNG ??留??낅줈??媛?ν빀?덈떎.');
