        const options = [{ value: '?먯쑉?섎젴', label: '?먯쑉?섎젴' }];

        if (dailyClasses.length > 0) {
            dailyClasses.forEach(cls => {
                const time = cls.time || '';
                const title = cls.title || cls.className || '';
