                    <div style={{ textAlign: 'center', background: 'rgba(255,255,255,0.02)', padding: '20px', borderRadius: '12px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                            <h3 style={{ margin: 0 }}>媛寃⑺몴 1</h3>
                            <input type="file" accept="image/*" onChange={e => handleImageUpload(e, 'price_table_1', setOptimisticImages)} style={{ display: 'none' }} id="up-price-1" />
                            <label htmlFor="up-price-1" className="action-btn sm"><Plus size={16} /> 蹂寃?/label>
                        </div>
                        <img src={getImage('price_table_1', config.ASSETS?.LOGO?.WIDE)} alt="媛寃⑺몴 1" style={{ width: '100%', borderRadius: '12px' }} />
                    </div>
                    <div style={{ textAlign: 'center', background: 'rgba(255,255,255,0.02)', padding: '20px', borderRadius: '12px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                            <h3 style={{ margin: 0 }}>媛寃⑺몴 2</h3>
                            <input type="file" accept="image/*" onChange={e => handleImageUpload(e, 'price_table_2', setOptimisticImages)} style={{ display: 'none' }} id="up-price-2" />
                            <label htmlFor="up-price-2" className="action-btn sm"><Plus size={16} /> 蹂寃?/label>
                        </div>
                        <img src={getImage('price_table_2', config.ASSETS?.LOGO?.WIDE)} alt="媛寃⑺몴 2" style={{ width: '100%', borderRadius: '12px' }} />
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useState, useEffect, useMemo, useRef } from 'react';
import { X } from '@phosphor-icons/react';
import { storageService } from '../../../services/storage';
import { useStudioConfig } from '../../../contexts/StudioContext';

const MemberAddModal = ({ isOpen, onClose, onSuccess }) => {
    const { config } = useStudioConfig();
    const branches = config.BRANCHES || [];
    const [pricingConfig, setPricingConfig] = useState(config.PRICING || {});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const isSubmittingRef = useRef(false);
    const [dailyClasses, setDailyClasses] = useState([]);

    const [newMember, setNewMember] = useState({
        name: '', phone: '010', branch: branches.length > 0 ? branches[0].id : '',
        membershipType: Object.keys(config.PRICING || {}).find(k => k !== '_meta') || 'general',
        selectedOption: '',
        duration: 1,
        paymentMethod: 'card',
        credits: 0,
        amount: 0,
        regDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
        startDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
        endDate: '',
        subject: '',
        autoStart: false,
        includeToday: false, // [NEW] Option for "Attended today"
        todayClass: null, // [NEW] To store matched class info
        notes: '' // [NEW] Member notes
    });

    useEffect(() => {
        const loadPricing = async () => {
            const data = await storageService.getPricing();
            if (data) setPricingConfig(data);
        };
        if (isOpen) loadPricing();
    }, [isOpen]);

    // [NEW] ?좏깮 吏?먯쓽 ?ㅻ뒛 ?섏뾽 紐⑸줉 媛?몄삤湲?r
    useEffect(() => {
        const fetchClasses = async () => {
            if (!isOpen || !newMember.branch) return;
            try {
                const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                const classes = await storageService.getDailyClasses(newMember.branch, null, today);
                setDailyClasses(classes || []);
            } catch (err) {
                console.warn('[MemberAddModal] Failed to fetch daily classes:', err);
                setDailyClasses([]);
            }
        };
        fetchClasses();
    }, [isOpen, newMember.branch]);

    // [Smart Calculation Logic for New Member]
    const { calculatedPrice, calculatedCredits, calculatedEndDate, calculatedRealEndDate, calculatedProductName } = useMemo(() => {
        if (!isOpen) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        const { membershipType, selectedOption, duration, paymentMethod, startDate, includeToday } = newMember;
        const category = pricingConfig[membershipType];

        if (!category) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        const option = category.options.find(opt => opt.id === selectedOption);
        if (!option) return { calculatedPrice: 0, calculatedCredits: 0, calculatedEndDate: '', calculatedRealEndDate: '', calculatedProductName: '' };

        let p = 0;
        let c = 0;
        let months = duration;
        let label = option.label;

        // Price Calculation with Cash/Transfer Price support
        // [FIX] ?댁껜(transfer)???꾧툑怨??숈씪??媛寃??곸슜
        const isCashLike = paymentMethod === 'cash' || paymentMethod === 'transfer';

        if (isCashLike && option.cashPrice !== undefined) {
            p = option.cashPrice;
            // [FIX] Preserve credits for cash payments if option defines it
            c = option.credits === 9999 ? 9999 : option.credits * duration;
            months = duration * (option.months || 1);
        } else {
            if (option.type === 'ticket') {
                p = option.basePrice;
                c = option.credits;
                months = option.months || 3;
            } else {
                c = option.credits === 9999 ? 9999 : option.credits * duration;
                months = duration * (option.months || 1);
                if (duration === 1) p = option.basePrice;
                else if (duration === 3) p = isCashLike && option.cashDiscount3 ? option.cashDiscount3 : (option.discount3 || (option.basePrice * 3));
                else if (duration === 6) p = isCashLike && option.cashDiscount6 ? option.cashDiscount6 : (option.discount6 || (option.basePrice * 6));
                else p = option.basePrice * duration;
            }

            if (isCashLike && duration >= 3 && p > 0 && !option.cashPrice && !option.cashDiscount3 && !option.cashDiscount6) {
                p = Math.round(p * 0.95);
            }
        }

        // [Logic] Deduct 1 credit if today is included
        if (includeToday && c > 0 && c !== 9999) {
            c -= 1;
        }

        const start = new Date(startDate);
        const end = new Date(start);
        end.setMonth(end.getMonth() + months);
        end.setDate(end.getDate() - 1);
        
        const realEnd = end.toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });

        return {
            calculatedPrice: p,
            calculatedCredits: c,
            calculatedEndDate: newMember.autoStart ? '泥?異쒖꽍 ???뺤젙' : (newMember.manualEndDate ? newMember.manualEndDate : realEnd),
            calculatedRealEndDate: newMember.manualEndDate ? newMember.manualEndDate : realEnd,
            calculatedProductName: `${label} ${duration > 1 && option.type !== 'ticket' ? `(${duration}媛쒖썡)` : ''}`
        };
    }, [newMember, pricingConfig, isOpen]);

    // Sync newMember state with calculated values
    useEffect(() => {
        if (!isOpen) return;
        setNewMember(prev => ({
            ...prev,
            amount: calculatedPrice,
            credits: calculatedCredits,
            endDate: calculatedEndDate,
            realEndDate: calculatedRealEndDate,
            subject: calculatedProductName,
            manualEndDate: '' // [FIX] ?쒖옉?쇱씠??寃곗젣湲곌컙 蹂寃????섎룞 留덇컧??珥덇린?뷀븯???먮룞怨꾩궛媛??몄텧 蹂댁옣
        }));
    }, [calculatedPrice, calculatedCredits, calculatedEndDate, calculatedRealEndDate, calculatedProductName, isOpen]);

    // pricingConfig/branch/紐⑤떖?대┝ 蹂寃???membershipType怨?selectedOption????긽 ?숈떆 寃利?r
    const getBranchName = (id) => branches.find(b => b.id === id)?.name || id;
    useEffect(() => {
        if (!isOpen) return;
        const validKeys = Object.keys(pricingConfig).filter(k => k !== '_meta');
        if (validKeys.length === 0) return;

        const branchName = getBranchName(newMember.branch);
        const availableTypes = validKeys.filter(key => {
            const cfg = pricingConfig[key];
            return !cfg?.branches || cfg.branches.includes(newMember.branch) || cfg.branches.includes(branchName);
        });
        if (availableTypes.length === 0) return;

        // 1) membershipType 寃利?r
        let targetType = newMember.membershipType;
        if (!availableTypes.includes(targetType)) {
            targetType = availableTypes[0];
        }

        // 2) selectedOption 寃利????꾩옱 ??낆쓽 ?듭뀡 紐⑸줉???ы븿?섏뼱 ?덈뒗吏
        // [FIX] 1?뚭텒(credits === 1 && type === 'ticket') ?쒖쇅
        const options = (pricingConfig[targetType]?.options || []).filter(opt => !(opt.type === 'ticket' && opt.credits === 1));
        const isOptionValid = newMember.selectedOption && options.some(opt => opt.id === newMember.selectedOption);

        const needsTypeChange = targetType !== newMember.membershipType;
        const needsOptionChange = !isOptionValid;

        if (needsTypeChange || needsOptionChange) {
            setNewMember(prev => ({
                ...prev,
                ...(needsTypeChange ? { membershipType: targetType } : {}),
                ...(needsOptionChange ? { selectedOption: options[0]?.id || '' } : {})
            }));
        }
    }, [newMember.branch, newMember.membershipType, newMember.selectedOption, isOpen, pricingConfig]);

    const handleAddMember = async () => {
        if (!newMember.name || !newMember.phone) {
            alert('?대쫫怨??꾪솕踰덊샇???꾩닔?낅땲??');
            return;
        }
        if (isSubmitting) return;

        isSubmittingRef.current = true;
        setIsSubmitting(true);
        try {
            const res = await storageService.addMember({
                name: newMember.name,
                phone: newMember.phone,
                credits: newMember.credits,
                homeBranch: newMember.branch,
                subject: newMember.subject,
                amount: newMember.amount,
                membershipType: newMember.membershipType,
                regDate: newMember.regDate,
                startDate: newMember.autoStart ? 'TBD' : newMember.startDate,
                endDate: newMember.autoStart ? 'TBD' : newMember.endDate,
                duration: newMember.duration,
                attendanceCount: newMember.includeToday ? 1 : 0, // [NEW] Mark initial attendance
                lastAttendance: newMember.includeToday ? new Date().toISOString() : null,
                notes: newMember.notes || ''
            });

            if (newMember.amount > 0) {
                await storageService.addSalesRecord({
                    memberId: res.id,
                    memberName: newMember.name,
                    type: 'register',
                    item: newMember.subject,
                    amount: newMember.amount,
                    paymentMethod: newMember.paymentMethod,
                    date: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
                    branchId: newMember.branch
                });
            }

            // [NEW] Automatically add attendance record if "Include Today" is checked
            if (newMember.includeToday) {
                // [FIX] ISO timestamp ???YYYY-MM-DD ?좎쭨瑜??꾨떖
                // ?댁쟾: new Date().toISOString() ??UTC 蹂?섎릺???쒕쾭?먯꽌 date/classTime???섎せ ??λ맖
                const todayDateStr = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
                await storageService.addManualAttendance(
                    res.id,
                    todayDateStr,
                    newMember.branch,
                    newMember.todayClass?.title || "?깅줉 ?뱀씪 ?섎젴",
                    newMember.todayClass?.instructor || "?쒖뒪???먮룞",
                    { skipCreditDeduction: true } // [FIX] ?대? credits 怨꾩궛 ??1??李④컧?? ?댁쨷 李④컧 諛⑹?
                );
            }

            onSuccess();
            onClose();
            // Reset form
            setNewMember({
                name: '', phone: '010', branch: branches.length > 0 ? branches[0].id : '',
                membershipType: Object.keys(pricingConfig).find(k => k !== '_meta') || 'general',
                selectedOption: '',
                duration: 1,
                paymentMethod: 'card',
                credits: 0, amount: 0, regDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }),
                startDate: new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }), endDate: '', subject: '', autoStart: false,
                includeToday: false,
                todayClass: null,
                manualEndDate: '',
                notes: ''
            });
        } catch (err) {
            console.error('Error adding member:', err);
            alert('?뚯썝 ?깅줉 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.');
        } finally {
            setIsSubmitting(false);
            isSubmittingRef.current = false;
        }
    };

    if (!isOpen) return null;

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()} style={{
                display: 'flex',
                flexDirection: 'column',
                gap: '12px',
                padding: 'var(--modal-padding, 24px)',
                width: '100%',
                maxWidth: '600px',
                margin: '0 auto',
                borderRadius: 'min(24px, 5vw)'
            }}>
                <div className="modal-header">
                    <h2 className="modal-title">?뚯썝 ?깅줉</h2>
                    <button onClick={onClose} style={{ color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <X size={24} weight="bold" />
                    </button>
                </div>
                <div className="form-group" style={{ marginBottom: '14px' }}>
                    <label className="form-label" style={{ marginBottom: '6px' }}>?대쫫</label>
                    <input className="form-input" style={{ fontFamily: 'var(--font-main)', padding: '14px 18px', fontSize: '1.1rem' }} value={newMember.name} onChange={(e) => setNewMember({ ...newMember, name: e.target.value })} lang="ko" inputMode="text" autoComplete="name" spellCheck="false" autoCorrect="off" placeholder="?뚯썝 ?대쫫 ?낅젰" />
                </div>
                <div className="form-group" style={{ marginBottom: '14px' }}>
                    <label className="form-label" style={{ marginBottom: '6px' }}>?꾪솕踰덊샇</label>
                    <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <span style={{ padding: '14px', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', color: 'var(--text-secondary)', fontFamily: 'var(--font-main)', fontWeight: 'bold' }}>010</span>
                        <input
                            className="form-input"
                            style={{ flex: 1, fontFamily: 'var(--font-main)', padding: '14px 18px', fontSize: '1.1rem' }}
                            placeholder="?룹옄由?8?먮━ ?レ옄"
                            maxLength={8}
                            inputMode="numeric"
                            value={newMember.phone.replace('010', '')}
                            onChange={(e) => {
                                const clean = e.target.value.replace(/[^0-9]/g, '');
                                setNewMember({ ...newMember, phone: '010' + clean });
                            }}
                        />
                    </div>
                </div>
                <div className="form-group">
                    <label className="form-label">吏??/label>
                    <select
                        className="form-select"
                        style={{ fontFamily: 'var(--font-main)' }}
                        value={newMember.branch}
                        onChange={(e) => {
                            const nextBranch = e.target.value;
                            setNewMember({ ...newMember, branch: nextBranch });
                        }}
                    >
                        {branches.map(b => (
                            <option key={b.id} value={b.id}>{b.name}</option>
                        ))}
                    </select>
                </div>
                <div className="form-group">
                    <label className="form-label">?뚯썝沅?醫낅쪟</label>
                    <select
                        className="form-select"
                        style={{ fontFamily: 'var(--font-main)' }}
                        value={newMember.membershipType}
                        onChange={e => {
                            const newType = e.target.value;
                            // [FIX] 1?뚭텒 ?쒖쇅??泥??듭뀡 ?좏깮
                            const filteredOpts = (pricingConfig[newType]?.options || []).filter(opt => !(opt.type === 'ticket' && opt.credits === 1));
                            const firstOptionId = filteredOpts[0]?.id || '';
                            setNewMember({ ...newMember, membershipType: newType, selectedOption: firstOptionId, duration: 1 });
                        }}
                    >
                        {Object.entries(pricingConfig)
                            .filter(([key, value]) => key !== '_meta' && (!value.branches || value.branches.includes(newMember.branch) || value.branches.includes(getBranchName(newMember.branch))))
                            .map(([key, value]) => (
                                <option key={key} value={key}>{value.label || key}</option>
                            ))}
                    </select>
                </div>
                <div className="form-group">
                    <label className="form-label">?몃? ?듭뀡</label>
                    <select
                        className="form-select"
                        style={{ fontFamily: 'var(--font-main)' }}
                        value={newMember.selectedOption}
                        onChange={e => setNewMember({ ...newMember, selectedOption: e.target.value })}
                    >
                        {pricingConfig[newMember.membershipType]?.options
                            .filter(opt => !(opt.type === 'ticket' && opt.credits === 1))
                            .map(opt => (
                            <option key={opt.id} value={opt.id}>{opt.label}</option>
                        ))}
                    </select>
                </div>

                {(() => {
                    const currentOption = pricingConfig[newMember.membershipType]?.options.find(o => o.id === newMember.selectedOption);
                    if (currentOption && currentOption.type === 'subscription') {
                        return (
                            <div className="form-group">
                                <label className="form-label">?깅줉 湲곌컙</label>
                                <div style={{ display: 'flex', gap: '8px' }}>
                                    {[1, 3, 6].map(m => (
                                        <button
                                            key={m}
                                            className={`action-btn ${newMember.duration === m ? 'primary' : ''}`}
                                            style={{ flex: 1, opacity: newMember.duration === m ? 1 : 0.4, padding: '14px 0', fontSize: '1rem', fontWeight: 'bold' }}
                                            onClick={() => setNewMember({ ...newMember, duration: m })}
                                        >
                                            {m}媛쒖썡
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )
                    }
                    return null;
                })()}

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                    <div className="form-group">
                        <label className="form-label">?깅줉??/label>
                        <div style={{ position: 'relative' }}>
                            <input
                                type="date"
                                className="form-input"
                                style={{ width: '100%', fontFamily: 'var(--font-main)', cursor: 'pointer' }}
                                value={newMember.regDate}
                                onClick={(e) => e.target.showPicker && e.target.showPicker()}
                                onChange={e => setNewMember({ ...newMember, regDate: e.target.value })}
                            />
                        </div>
                    </div>
                    <div className="form-group">
                        <label className="form-label" style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', justifyContent: 'space-between', alignItems: 'center' }}>
                            <span>?섎젴 ?쒖옉??/span>
                        </label>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                <label style={{
                                    flex: 1,
                                    padding: '12px 8px',
                                    borderRadius: '10px',
                                    background: newMember.autoStart ? 'rgba(var(--primary-rgb), 0.15)' : 'rgba(255,255,255,0.05)',
                                    border: `1px solid ${newMember.autoStart ? 'var(--primary-gold)' : 'transparent'}`,
                                    fontSize: '0.8rem',
                                    color: newMember.autoStart ? 'var(--primary-gold)' : 'var(--text-secondary)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    gap: '6px',
                                    cursor: 'pointer',
                                    transition: 'all 0.2s',
                                    fontWeight: newMember.autoStart ? 'bold' : 'normal'
                                }}>
                                    <input
                                        type="checkbox"
                                        style={{ width: '16px', height: '16px' }}
                                        checked={newMember.autoStart}
                                        onChange={e => setNewMember({
                                            ...newMember,
                                            autoStart: e.target.checked,
                                            includeToday: e.target.checked ? false : newMember.includeToday
                                        })}
                                    />
                                    泥?異쒖꽍???쒖옉
                                </label>
                                <label style={{
                                    flex: 1,
                                    padding: '12px 8px',
                                    borderRadius: '10px',
                                    background: newMember.includeToday ? 'rgba(76,175,80,0.15)' : 'rgba(255,255,255,0.05)',
                                    border: `1px solid ${newMember.includeToday ? '#4CAF50' : 'transparent'}`,
                                    fontSize: '0.8rem',
                                    color: newMember.includeToday ? '#4CAF50' : 'var(--text-secondary)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    gap: '6px',
                                    cursor: 'pointer',
                                    transition: 'all 0.2s',
                                    fontWeight: newMember.includeToday ? 'bold' : 'normal'
                                }}>
                                    <input
                                        type="checkbox"
                                        style={{ width: '16px', height: '16px' }}
                                        checked={newMember.includeToday}
                                        onChange={async (e) => {
                                            const isChecked = e.target.checked;
                                            let matchedClass = null;

                                            if (isChecked) {
                                                try {
                                                    const typeHint = pricingConfig[newMember.membershipType]?.label;
                                                    matchedClass = await storageService.getCurrentClass(newMember.branch, null, typeHint);
                                                } catch (err) {
                                                    console.error("Failed to fetch today's class during registration", err);
                                                }
                                            }

                                            setNewMember({
                                                ...newMember,
                                                includeToday: isChecked,
                                                todayClass: matchedClass,
                                                autoStart: isChecked ? false : newMember.autoStart,
                                                startDate: isChecked ? new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' }) : newMember.startDate
                                            });
                                        }}
                                    />
                                    ?ㅻ뒛 ?섎젴 ?ы븿
                                </label>
                            </div>

                            {/* [CRITICAL FIX] ??긽 ?좎쭨 ?낅젰 ?꾨뱶瑜??몄텧?섎룄濡??섏젙 (?ъ슜???쇰뱶諛?諛섏쁺) */}
                            <input
                                type="date"
                                className="form-input fade-in"
                                style={{ 
                                    width: '100%', 
                                    cursor: newMember.autoStart ? 'not-allowed' : 'pointer',
                                    opacity: newMember.autoStart ? 0.6 : 1
                                }}
                                value={newMember.startDate}
                                disabled={newMember.autoStart}
                                onClick={(e) => !newMember.autoStart && e.target.showPicker && e.target.showPicker()}
                                onChange={e => setNewMember({ ...newMember, startDate: e.target.value })}
                            />

                            {newMember.includeToday && (
                                <div className="fade-in" style={{ marginTop: '6px' }}>
                                    <select
                                        className="form-select"
                                        style={{ 
                                            width: '100%', 
                                            padding: '12px 14px', 
                                            fontSize: '0.9rem', 
                                            background: 'rgba(76,175,80,0.1)', 
                                            border: '1px solid rgba(76,175,80,0.3)', 
                                            borderRadius: '10px', 
                                            color: '#81C784', 
                                            fontWeight: 'bold',
                                            cursor: 'pointer'
                                        }}
                                        value={(() => {
                                            const cls = newMember.todayClass;
                                            if (!cls) return '?먯쑉?섎젴';
                                            return cls.title || '?먯쑉?섎젴';
                                        })()}
                                        onChange={(e) => {
                                            const selectedTitle = e.target.value;
                                            if (selectedTitle === '?먯쑉?섎젴') {
                                                setNewMember({ ...newMember, todayClass: null });
                                            } else {
