                                        </div>
                                    )}
                                </>
                            );
                        })()}
                    </div>
                </CollapsibleCard>
            )}
        </div>

            {lightboxImage && (
                <ImageLightbox src={lightboxImage} onClose={() => setLightboxImage(null)} />
            )}
    </>
    );
};

