    }, [filteredMembers, filterType, getDormantSegments, localSort]);

    if (!summary || !filteredMembers) return <div style={{ padding: '20px', textAlign: 'center', color: 'var(--text-secondary)' }}>?곗씠??濡쒕뵫 以?..</div>;
