import React, { useState, useEffect, memo } from 'react';
import { useStudioConfig } from '../../contexts/StudioContext';
import { toKSTDateString, toKSTTimeString, getTodayKST, safeParseDate } from '../../utils/dates';
import { CHECKIN_CONFIG } from '../../constants/CheckInConfig';

const SelectionModal = memo(({ 
    show, 
    duplicateMembers, 
    loading, 
    onClose, 
    onSelect 
}) => {
    const [selectedMemberId, setSelectedMemberId] = useState(null);
    const { config } = useStudioConfig();
    const [timeLeft, setTimeLeft] = useState(CHECKIN_CONFIG.TIMEOUTS.AUTO_CLOSE_MODAL / 1000);

    useEffect(() => {
        if (!show) {
            setSelectedMemberId(null);
            setTimeLeft(CHECKIN_CONFIG.TIMEOUTS.AUTO_CLOSE_MODAL / 1000);
            return;
        }
        if (loading) return; // 濡쒕뵫 以묒뿉????대㉧ ?뺤?

        const timerId = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    clearInterval(timerId);
                    onClose();
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);

        return () => clearInterval(timerId);
    }, [show, loading, onClose]);

    if (!show) return null;

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const activeMembers = [];
    const inactiveMembers = [];

    duplicateMembers.forEach(m => {
        const credits = m.credits || 0;
        const endDateStr = m.endDate;

        // 1. Check Credits
        const hasCredits = credits > 0 || credits === Infinity;

        // 2. Check Date
        let hasValidDate = true;
        if (endDateStr && endDateStr !== 'unlimited' && endDateStr !== 'TBD') {
            const parsedStr = typeof endDateStr === 'string' ? endDateStr.replace(/-/g, '/') : endDateStr;
            const endDate = new Date(parsedStr);
            endDate.setHours(23, 59, 59, 999); 
            if (endDate < today) {
                hasValidDate = false;
            }
        }

        if (hasCredits && hasValidDate) {
            activeMembers.push(m);
        } else {
            inactiveMembers.push(m);
        }
    });

    const handleConfirm = (e) => {
        if (loading || !selectedMemberId) return;
        e.stopPropagation();
        onSelect(selectedMemberId);
    };

    return (
        <div
            className="modal-overlay"
            onClick={(e) => e.stopPropagation()}
            onTouchStart={(e) => {
                if (e.cancelable) e.preventDefault();
                e.stopPropagation();
            }}
            style={{ zIndex: 3000, touchAction: 'none' }}
        >
            <div className="modal-content glass-panel" style={{
                width: '95%',
                maxWidth: '1100px',
                maxHeight: '90vh',
                padding: '25px 30px',
                display: 'flex',
                flexDirection: 'column',
                gap: '12px',
                overflow: 'hidden'
            }}>
                <h2 style={{ fontSize: '2rem', marginBottom: '5px', textAlign: 'center' }}>?뚯썝 ?좏깮</h2>
                <p style={{ textAlign: 'center', opacity: 0.7, marginBottom: '10px', fontSize: '0.95rem' }}>
                    ?대떦?섎뒗 ?뚯썝?섏쓣 ?좏깮?댁＜?몄슂
                    <span style={{ marginLeft: '10px', fontSize: '0.85em', color: '#ff6b6b' }}>
                        ({timeLeft}珥????먮룞 痍⑥냼)
                    </span>
                </p>

                <div style={{ display: 'flex', gap: '20px', flex: 1, minHeight: '280px' }}>
                    <div style={{ flex: 2, display: 'flex', flexDirection: 'column', gap: '10px' }}>
                        <h3 style={{ fontSize: '1.2rem', color: 'var(--primary-gold)', borderBottom: '1px solid rgba(var(--primary-rgb), 0.3)', paddingBottom: '8px' }}>
                            ???댁슜 媛???뚯썝
                        </h3>
                        <div style={{
                            display: 'flex',
                            flexWrap: 'wrap',
                            gap: '15px',
                            flex: 1,
                            overflowY: 'auto',
                            alignContent: 'start',
                            padding: '15px'
                        }}>
                            {activeMembers.length > 0 ? activeMembers.map(m => {
                                const isSelected = selectedMemberId === m.id;
                                return (
                                    <button
                                        key={m.id}
                                        onClick={(e) => {
                                            if (loading) return;
                                            e.stopPropagation();
                                            setSelectedMemberId(m.id);
                                        }}
                                        className={`member-card active-member-card ${isSelected ? 'selected' : ''}`}
                                        style={{
                                            flex: '1 1 calc(50% - 15px)',
                                            minWidth: '220px',
                                            padding: '20px',
                                            borderRadius: '16px',
                                            background: isSelected ? 'linear-gradient(135deg, rgba(var(--primary-rgb), 0.15), rgba(var(--primary-rgb), 0.05))' : 'linear-gradient(135deg, rgba(255,255,255,0.1), rgba(255,255,255,0.02))',
                                            color: 'white',
                                            border: isSelected ? '2px solid var(--primary-gold)' : '2px solid rgba(255,255,255,0.2)',
                                            boxShadow: isSelected ? '0 0 20px rgba(var(--primary-rgb), 0.3)' : '0 4px 15px rgba(0,0,0,0.1)',
                                            display: 'flex',
                                            flexDirection: 'column',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            gap: '12px',
                                            cursor: 'pointer',
                                            transition: 'all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                                            transform: isSelected ? 'scale(1.02)' : 'scale(1)',
                                            minHeight: '140px'
                                        }}
                                    >
                                        <span style={{ fontSize: '1.9rem', fontWeight: '800', color: isSelected ? 'var(--primary-gold)' : 'white' }}>{m.name}</span>
                                        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', justifyContent: 'center' }}>
                                            <span style={{ fontSize: '0.9rem', background: 'rgba(0,0,0,0.5)', padding: '5px 12px', borderRadius: '50px' }}>
                                                {config.BRANCHES?.find(b => b.id === m.homeBranch)?.name || m.homeBranch}
                                            </span>
                                            <span style={{ fontSize: '0.9rem', background: isSelected ? 'rgba(76, 175, 80, 0.3)' : 'rgba(255,255,255,0.1)', padding: '5px 12px', borderRadius: '50px', color: isSelected ? '#a5d6a7' : 'rgba(255,255,255,0.8)' }}>
                                                {m.credits > 900 ? '臾댁젣?? : `${m.credits}??}
                                            </span>
                                        </div>
                                    </button>
                                );
                            }) : (
                                <div style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0.5, fontSize: '1.2rem', padding: '30px' }}>
                                    ?쒖꽦 ?뚯썝???놁뒿?덈떎.
                                </div>
                            )}
                        </div>
