                         const { outcome } = await e.userChoice;
                         if (outcome === 'accepted') setIsStandalone(true);
                     } catch (err) {
                         console.error("Auto PWA prompt failed", err);
                     }
                 }, 2000); // UI ?덉젙????2珥????먮룞 ?ㅽ뻾
