                                                                    }}>
                                                                        {b.status === 'attended' ? '?? : b.status === 'noshow' ? '?? : b.status === 'waitlisted' ? '?? : '?뱥'} {b.memberName}
                                                                    </span>
                                                                ))}
                                                            </div>
                                                        </div>
