                    }}
                    style={{ width: '100%', accentColor: '#4ade80', height: '4px' }} />
            </div>
            
            {/* Binaural Volume */}
            <div>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                    <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.7)' }}>?렦 二쇳뙆??/span>
