    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const loadPoses = async () => {
            setLoading(true);
            try {
                // MBTI瑜?AI 紐⑤뜽???꾨떖?섏뿬 留욎땄 ?앹꽦
                const data = await storageService.getDailyYoga(language, mbti || null);
