                            </div>
                        </div>

                        <div style={{ padding: '12px 16px', background: 'rgba(251, 146, 60, 0.08)', borderRadius: '12px', marginBottom: '20px', fontSize: '0.75rem', color: 'rgba(255,255,255,0.6)', lineHeight: '1.6' }}>
