");
        handleChatResponse(text);
    }, [manualInput, handleChatResponse]);

    const handleReturnToChat = useCallback(async () => {
        setIsAILoading(true);
        
        const warmReconnectMsg = `${memberName}?? ?ㅼ떆 ?뚯븘?ㅼ뀲?ㅼ슂. ?뱀떆 ???섎늻怨??띠? ?댁빞湲곌? ?덉쑝?좉???`;
        setCurrentAIChat({
            message: warmReconnectMsg,
            options: ["?? ?덉뼱??

${lastUserMsg}". Gently ask if they want to explore that topic more deeply, in a warm, human, conversational tone. Do NOT sound robotic or templated.` 
