            }
            return result.data;
        } catch (err) {
            console.error('AI Feedback Failed:', err);
            return null;
        }
    }, [memberName, sessionInfo]);

    // Helpers
    const generateReason = useCallback((time, weatherId, diagnosisId) => {
        const timeText = time === 'morning' ? '?섎（瑜??쒖옉?섎뒗 ?꾩묠,' : time === 'afternoon' ? '?먮꼫吏媛 ?꾩슂???ㅽ썑,' : '?섎（瑜??뺣━?섎뒗 諛?';
