        } else if (diagnosisId === 'stiff') {
            coreMessage = "紐몄쓽 湲댁옣? 留덉쓬??蹂대궡???좏샇?덉슂. 援녹뼱?덈뜕 洹쇱쑁???섏떇?곸쑝濡??댁셿?섎ŉ ?명씉?섎㈃, 留됲삍???먮꼫吏媛 ?먮Ⅴ湲??쒖옉??嫄곗삁??";
        } else if (diagnosisId === 'anxious' || diagnosisId === 'frustrated') {
            coreMessage = "?듬떟?섍퀬 遺덉븞??留덉쓬? ?꾧뎄??媛吏????덈뒗 援щ쫫 媛숈? 嫄곗삁?? 洹?援щ쫫 ?ㅼ뿉 ?덈뒗 留묒? ?섎뒛??蹂????덈룄濡??쒓? 怨곸뿉???꾩??쒕┫寃뚯슂. ?뱀떊? ?덉쟾?⑸땲??";
        } else if (diagnosisId === 'tired' || diagnosisId === 'low_energy') {
            coreMessage = "?먮꼫吏媛 遺議깊븷 ?뚮뒗 ?듭?濡??몃젰???꾩슂 ?놁뼱?? 洹몄? ?몄븞???됱븘 ?덈뒗 寃껊쭔?쇰줈??異⑸텇??紐낆긽???⑸땲?? ?뱀떊??吏移?留덉쓬???곕쑜?섍쾶 ?덉븘以꾧쾶??";
        } else if (diagnosisId === 'distracted') {
            coreMessage = "?⑹뼱吏?留덉쓬???섎굹濡?紐⑥쑝???곗뒿???대낵源뚯슂? ?명씉?대씪???살쓣 ?대━怨?'吏湲??ш린'濡??뚯븘?ㅻ뒗 ?ъ젙???쒖옉?대킄??";
        } 
        return `${timeText} ${coreMessage}`;
    }, []);

    return {
        isAILoading, setIsAILoading,
        aiRequestLock, setAiRequestLock,
        aiLatency, setAiLatency,
        chatHistory, setChatHistory,
        currentAIChat, setCurrentAIChat,
        manualInput, setManualInput,
        aiPrescription, setAiPrescription,
        prescriptionReason, setPrescriptionReason,
        aiMessage, setAiMessage,
        sessionInfo, setSessionInfo,
        feedbackData, setFeedbackData,

        
        messageIndexRef,
        sessionDiagnosisRef,
        consecutiveFailsRef,

        fetchAIPrescription,
        fetchAIQuestion,
        fetchAISessionMessage,
        fetchAIFeedback,
        handleChatResponse,
        handleManualSubmit,
        handleReturnToChat,
        generateReason
    };
};

