import { useRef, useCallback, useEffect } from 'react';

export const useMeditationAudio = (ttcEnabled, isPlayingRef, step, logDebug, setTtsState, audioVolumes, soundEnabled) => {
    const audioContextRef = useRef(null);
    const oscLeftRef = useRef(null);
    const oscRightRef = useRef(null);
    const gainNodeRef = useRef(null);
    const currentAudioRef = useRef(null);
    const ambientAudioRef = useRef(null);

    // Audio Context Getter
    const getAudioContext = useCallback(() => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        return audioContextRef.current;
    }, []);

    // ---------------------------------------------------------
    // 1. Binaural Beats Engine
    // ---------------------------------------------------------
    const playBinauralBeats = useCallback((carrierFreq = 200, beatFreq = 4, volume = 0.25) => {
        const audioCtx = getAudioContext();
        if (audioCtx.state === 'suspended') audioCtx.resume();

        const oscL = audioCtx.createOscillator();
        const oscR = audioCtx.createOscillator();
        const gainNode = audioCtx.createGain();

        oscL.type = 'sine'; oscR.type = 'sine';
        oscL.frequency.value = carrierFreq;
        oscR.frequency.value = carrierFreq + beatFreq;

        const pannerL = audioCtx.createStereoPanner();
        const pannerR = audioCtx.createStereoPanner();
        pannerL.pan.value = -1; pannerR.pan.value = 1;

        oscL.connect(pannerL); pannerL.connect(gainNode);
        oscR.connect(pannerR); pannerR.connect(gainNode);

        gainNode.connect(audioCtx.destination);
        gainNode.gain.value = volume;

        oscL.start(); oscR.start();

        oscLeftRef.current = oscL;
        oscRightRef.current = oscR;
        gainNodeRef.current = gainNode;
        
        logDebug && logDebug("BinauralBeats:Start", { carrierFreq, beatFreq, volume });
    }, [getAudioContext, logDebug]);

    const stopBinauralBeats = useCallback(() => {
        if (oscLeftRef.current) { try { oscLeftRef.current.stop(); } catch { /* ignore */ } oscLeftRef.current = null; }
        if (oscRightRef.current) { try { oscRightRef.current.stop(); } catch { /* ignore */ } oscRightRef.current = null; }
        if (gainNodeRef.current) gainNodeRef.current = null;
    }, []);

    const updateBinauralVolume = useCallback((volume) => {
        if (gainNodeRef.current && audioContextRef.current) {
            const currentTime = audioContextRef.current.currentTime;
            gainNodeRef.current.gain.setTargetAtTime(volume, currentTime, 0.5);
        }
    }, []);

    // ---------------------------------------------------------
    // 2. Ambient Environments Engine
    // ---------------------------------------------------------
    const updateAmbientVolume = useCallback((volume) => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.volume = volume;
        }
    }, []);

    const playAmbientMusic = useCallback((ambientDef, volume) => {
        if (!ambientDef || ambientDef.id === 'none') {
            if (ambientAudioRef.current) {
                ambientAudioRef.current.pause();
                ambientAudioRef.current = null;
            }
            return;
        }

        if (!ambientAudioRef.current || !ambientAudioRef.current.src.includes(ambientDef.audioUrl)) {
            if (ambientAudioRef.current) ambientAudioRef.current.pause();
            const audio = new Audio(ambientDef.audioUrl);
            audio.loop = true;
            audio.volume = volume;
            ambientAudioRef.current = audio;
        }

        ambientAudioRef.current.play().catch(e => {
            console.warn("Ambient play failed:", e);
            logDebug && logDebug("Ambient:Error", e);
        });
    }, [logDebug]);

    const stopAmbientMusic = useCallback(() => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.pause();
        }
    }, []);

    const stopAmbientMusicAndReset = useCallback(() => {
        if (ambientAudioRef.current) {
            ambientAudioRef.current.pause();
            ambientAudioRef.current.currentTime = 0;
            ambientAudioRef.current = null;
        }
    }, []);

    // ---------------------------------------------------------
    // 3. TTS Engines (Cloud & Local)
    // ---------------------------------------------------------
    const stopVoiceOnly = useCallback(() => {
        if (window.speechSynthesis) window.speechSynthesis.cancel();
        if (currentAudioRef.current) {
            try { currentAudioRef.current.pause(); currentAudioRef.current.currentTime = 0; } catch { /* ignore */ }
            currentAudioRef.current = null;
        }
    }, []);

    const playAudio = useCallback((base64String, customVolume, onEndedCallback) => {
        if (!ttcEnabled || !base64String) return null;
        
        try {
            stopVoiceOnly();
            
            const audio = new Audio(`data:audio/mp3;base64,${base64String}`);
            audio.volume = customVolume !== undefined ? customVolume : (soundEnabled ? audioVolumes.voice : 0);
            currentAudioRef.current = audio;

            setTtsState && setTtsState({ isSpeaking: true, engine: 'Cloud TTS', volume: audio.volume });
            logDebug && logDebug("PlayAudio:Start", { vol: audio.volume });

            audio.onended = () => { 
                logDebug && logDebug("PlayAudio:Ended");
                setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
                if (currentAudioRef.current === audio) currentAudioRef.current = null;
                if (onEndedCallback) onEndedCallback();
            };
            
            const playPromise = audio.play();
            if (playPromise !== undefined) {
                playPromise.catch(e => {
                    console.error("?뵄 Audio Playback Failed:", e);
                    logDebug && logDebug("PlayAudio:Error", e);
                    setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
                });
            }
            
            // [FIX] More robust race condition check to ensure audio isn't prematurely paused
            // Only pause if we are explicitly IN a session and the user has actively hit pause.
            if (step === 'session' && isPlayingRef && isPlayingRef.current === false) {
                audio.pause();
                currentAudioRef.current = null;
            }
            
            return audio;
        } catch (e) {
            console.error("?뵄 Audio Error:", e);
            logDebug && logDebug("PlayAudio:Catch", e);
            setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
            return null;
        }
    }, [ttcEnabled, stopVoiceOnly, setTtsState, logDebug, isPlayingRef, step]);

    const speak = useCallback((text) => {
        logDebug && logDebug("Speak:Start", text);
        console.log("?뿣截?[TTS Check] Speaking:", text);
        if (!text || typeof window === 'undefined' || !ttcEnabled || !window.speechSynthesis) return;
        
        stopVoiceOnly(); 
        
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'ko-KR';
        utterance.rate = 0.9;
        utterance.pitch = 1.0;
        utterance.volume = 0.8;

        utterance.onstart = () => setTtsState && setTtsState({ isSpeaking: true, engine: 'Local TTS', volume: 0.8 });
        utterance.onend = () => setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
        utterance.onerror = () => setTtsState && setTtsState(prev => ({ ...prev, isSpeaking: false }));
        
        setTimeout(() => {
            if (window.speechSynthesis && ttcEnabled && (step !== 'session' || isPlayingRef.current)) {
                window.speechSynthesis.speak(utterance);
            }
        }, 100);
    }, [ttcEnabled, step, stopVoiceOnly, logDebug, setTtsState, isPlayingRef]);

    const speakFallback = useCallback((text) => {
        if (!text || typeof window === 'undefined' || !ttcEnabled || !window.speechSynthesis) return;
        
        logDebug && logDebug("SpeakFallback", text);
        stopVoiceOnly();

        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = 'ko-KR';
        utterance.rate = 0.9;
        utterance.pitch = 1.0; 
        utterance.volume = 0.8; 
        
        setTimeout(() => {
            if (window.speechSynthesis && ttcEnabled) {
                window.speechSynthesis.speak(utterance);
            }
        }, 100);
    }, [ttcEnabled, stopVoiceOnly, logDebug]);

    // ---------------------------------------------------------
    // 4. Global Cleanup
    // ---------------------------------------------------------
    const stopAllAudio = useCallback((stopAmbient = false) => {
        stopVoiceOnly();
        
        if (stopAmbient) stopAmbientMusic();
        
        stopBinauralBeats();
        
        logDebug && logDebug("StopAllAudio", { stopAmbient });
    }, [stopVoiceOnly, stopAmbientMusic, stopBinauralBeats, logDebug]);

    // Cleanup AudioContext on unmount
    useEffect(() => {
        return () => {
            if (audioContextRef.current) {
                audioContextRef.current.close().catch(e => console.error(e));
                audioContextRef.current = null;
            }
        };
    }, []);

    // Provide raw refs to caller if needed
    return {
        audioContextRef,
        ambientAudioRef,
        currentAudioRef,
        
        getAudioContext,
        playBinauralBeats,
        stopBinauralBeats,
        updateBinauralVolume,
        playAmbientMusic,
        stopAmbientMusic,
        stopAmbientMusicAndReset,
        updateAmbientVolume,
        playAudio,
        speak,
        speakFallback,
        stopVoiceOnly,
        stopAllAudio
    };
};

/**
 * useMemberData ??Data loading, real-time subscriptions, AI/Weather for MemberProfile
 * Extracted from MemberProfile.jsx to reduce its 1,162-line bulk by ~300 lines.
 */
import { useState, useEffect, useRef } from 'react';
import { onSnapshot, query, where, orderBy, limit as firestoreLimit } from 'firebase/firestore';
import { auth } from '../firebase';
import { tenantDb } from '../utils/tenantDb';
import { storageService } from '../services/storage';
import { safeLocalStorage } from '../utils/safeLocalStorage';
import { getDaysRemaining, getKSTHour, getKSTMonth, getKSTDayNameEN } from '../utils/dates';

/**
 * @param {Object} options
 * @param {Function} options.t - Translation function
 * @param {string} options.language - Current language code
 * @param {Function} options.setLoginFormValue - Setter for login form values
 * @returns {Object} Member data state and handlers
 */
export function useMemberData({ t, language, setLoginFormValue, setLoginForm }) {
  const [member, setMember] = useState(null);
  const [loading, setLoading] = useState(true);
  const [logs, setLogs] = useState([]);
  const [logLimit, setLogLimit] = useState(10);
  const [notices, setNotices] = useState([]);
  const [images, setImages] = useState({});
  const [weatherData, setWeatherData] = useState(null);
  const [aiExperience, setAiExperience] = useState(null);
  const [aiAnalysis, setAiAnalysis] = useState(null);
  const [individualMessages, setIndividualMessages] = useState([]);
  const [messages, setMessages] = useState([]);
  const [pushStatus, setPushStatus] = useState(() => {
    if (typeof Notification === 'undefined') return 'default';
    return Notification.permission;
  });

  // AI dedup refs
  const lastAiExpArgs = useRef('');
  const lastAiAnalysisArgs = useRef('');

  // ?? Traditional yoga greeting fallback ??
  const getTraditionalYogaMessage = () => {
    const hour = getKSTHour();
    const month = getKSTMonth();
    let timeMsg = '';
    if (hour >= 5 && hour < 9) timeMsg = t('trad_dawn');
    else if (hour >= 9 && hour < 12) timeMsg = t('trad_morning');
    else if (hour >= 12 && hour < 17) timeMsg = t('trad_afternoon');
    else if (hour >= 17 && hour < 21) timeMsg = t('trad_evening');
    else timeMsg = t('trad_night');

    let seasonMsg = '';
    if (month >= 3 && month <= 5) seasonMsg = t('season_spring');
    else if (month >= 6 && month <= 8) seasonMsg = t('season_summer');
    else if (month >= 9 && month <= 11) seasonMsg = t('season_autumn');
    else seasonMsg = t('season_winter');
    return timeMsg + seasonMsg;
  };

  // ?? AI Experience Loader ??
  const loadAIExperience = async (m, attendanceData = null, wData = null) => {
    if (!m) return;
    if (aiExperience && !aiExperience.isFallback) return;

    const hour = getKSTHour();
    const day = getKSTDayNameEN();

    const validAttendance = attendanceData ? attendanceData.filter(l => l.status !== 'denied') : [];
    const currentArgs = `${m.id}_${validAttendance.length}_${day}_${hour}_${wData?.key || 'null'}_${language}`;
    if (lastAiExpArgs.current === currentArgs) return;
    lastAiExpArgs.current = currentArgs;

    try {
      const streak = attendanceData ? storageService.getMemberStreak(m.id, validAttendance) : 0;
      const lastAtt = validAttendance.length > 0 ? (validAttendance[0].timestamp || validAttendance[0].date) : null;

      const exp = await storageService.getAIExperience(
        m.name, m.attendanceCount || validAttendance.length, day, hour,
        null,
        wData ? `${t('weather_' + wData.key)} (${wData.temp}째C)` : 'Sunny',
        m.credits || 0, getDaysRemaining(m.endDate), language,
        { streak, lastAttendanceAt: lastAtt }, 'profile'
      );
      if (exp) {
        setAiExperience(exp);
        storageService.setGreetingCache(m.id, { ...exp, _cachedForName: m.name });
      }
    } catch {
      setAiExperience({ message: getTraditionalYogaMessage(), bgTheme: 'sunny' });
    }
  };

  // ?? Weather Fetcher ??
  const fetchWeather = async () => {
    try {
      const res = await fetch('https://api.open-meteo.com/v1/forecast?latitude=37.5665&longitude=126.9780&current_weather=true');
      const data = await res.json();
      const wc = data.current_weather.weathercode;
      let key = 'clear';
      if (wc >= 1 && wc <= 3) key = 'partly_cloudy';
      if (wc > 3) key = 'cloudy';
      if (wc >= 45 && wc <= 48) key = 'fog';
      if (wc >= 51 && wc <= 67) key = 'rain';
      if (wc >= 71 && wc <= 77) key = 'snow';
      if (wc >= 95) key = 'thunderstorm';

      const wData = { key, temp: data.current_weather.temperature };
      setWeatherData(wData);
      return wData;
    } catch {
      return null;
    }
  };

  // ?? Core data loader ??
  const loadMemberData = async (memberId) => {
    try {
      setLoading(true);
      const [memberData, history, noticeData, imagesData, messagesData] = await Promise.all([
        storageService.fetchMemberById(memberId),
        storageService.getAttendanceByMemberId(memberId),
        storageService.loadNotices(),
        storageService.getImages(),
        storageService.getMessagesByMemberId(memberId)
      ]);

      if (memberData) {
        setMember(prev => ({
          ...memberData,
          displayName: prev?.displayName || JSON.parse(safeLocalStorage.getItem('member') || '{}').displayName || memberData.name
        }));

        const sortedHistory = (history || []).sort((a, b) => new Date(b.timestamp || b.date || 0) - new Date(a.timestamp || a.date || 0));
        setLogs(sortedHistory);
        setIndividualMessages(messagesData || []);

        const sortedNotices = (noticeData || []).sort((a, b) => new Date(b.timestamp || b.date || 0) - new Date(a.timestamp || a.date || 0));
        setNotices(sortedNotices);
        setImages(imagesData || {});

        const validHistory = history.filter(h => h.status !== 'denied');

        const wData = await fetchWeather();
        loadAIExperience(memberData, validHistory, wData);

        const currentAnalysisArgs = `${memberData.name}_${validHistory.length}_${getKSTHour()}_${language}`;
        if (lastAiAnalysisArgs.current !== currentAnalysisArgs) {
          lastAiAnalysisArgs.current = currentAnalysisArgs;
          storageService.getAIAnalysis(memberData.name, validHistory.length, validHistory, getKSTHour(), language, 'member')
            .then(analysis => setAiAnalysis(analysis))
            .catch(() => setAiAnalysis({ message: t('analysisPending'), isError: true }));
        }

        // Push self-healing
        if (typeof Notification !== 'undefined' && (Notification.permission === 'granted' || localStorage.getItem('push_enabled') === 'true')) {
          storageService.requestPushPermission(memberId).catch(() => {});
          setPushStatus('granted');
        }
      } else {
        setLoginFormValue('error', t('errorMemberNotFound'));
