import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { verifyPasswordResetCode, confirmPasswordReset } from 'firebase/auth';
import { auth } from '../firebase';
import './AuthActionPage.css';

const AuthActionPage = () => {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();

    const mode = searchParams.get('mode');
    const oobCode = searchParams.get('oobCode');

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [email, setEmail] = useState('');

    // Form states
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        if (!mode || !oobCode) {
            setError('?좏슚?섏? ?딆? ?붿껌?낅땲?? 留곹겕媛 ?щ컮瑜몄? ?ㅼ떆 ?뺤씤?댁＜?몄슂.');
            setLoading(false);
            return;
        }

        if (mode === 'resetPassword') {
            // ?뷀샇 肄붾뱶 寃利?諛??대찓??二쇱냼 媛?몄삤湲?n            verifyPasswordResetCode(auth, oobCode)
                .then((resolvedEmail) => {
                    setEmail(resolvedEmail);
                    setLoading(false);
                })
                .catch((err) => {
                    console.error('Verify error:', err);
                    setError('留뚮즺?섏뿀嫄곕굹 ?좏슚?섏? ?딆? 鍮꾨?踰덊샇 ?ъ꽕??留곹겕?낅땲?? ?먯옣?섍퍡 ?덈줈??留곹겕 諛쒓툒???붿껌?댁＜?몄슂.');
                    setLoading(false);
                });
        } else {
            setError(`吏?먰븯吏 ?딅뒗 ?몄쬆 紐⑤뱶?낅땲?? ${mode}`);
            setLoading(false);
        }
    }, [mode, oobCode]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (newPassword.length < 6) {
            alert('鍮꾨?踰덊샇??理쒖냼 6???댁긽?댁뼱???⑸땲??');
            return;
        }
        if (newPassword !== confirmPassword) {
            alert('鍮꾨?踰덊샇媛 ?쒕줈 ?쇱튂?섏? ?딆뒿?덈떎.');
            return;
        }

        setIsSubmitting(true);
        try {
            await confirmPasswordReset(auth, oobCode, newPassword);
            setSuccess(true);
        } catch (err) {
            console.error('Confirm error:', err);
            alert('鍮꾨?踰덊샇 蹂寃쎌뿉 ?ㅽ뙣?덉뒿?덈떎: ' + err.message);
        }
        setIsSubmitting(false);
    };

    if (loading) {
        return (
            <div className="auth-action-container loading">
                <div className="spinner"></div>
                <p>?몄쬆 ?뺣낫瑜??뺤씤?섎뒗 以묒엯?덈떎...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="auth-action-container">
                <div className="auth-card error">
                    <div className="logo-placeholder">PassFlow Ai</div>
                    <h2>?묎렐 ?ㅻ쪟</h2>
                    <p className="error-text">{error}</p>
                    <button className="back-btn" onClick={() => navigate('/login')}>濡쒓렇???붾㈃?쇰줈 ?뚯븘媛湲?/button>
                </div>
            </div>
        );
    }

    if (success) {
        return (
            <div className="auth-action-container">
                <div className="auth-card success">
                    <img src="/logo192.png" alt="PassFlow Logo" className="pf-logo" onError={(e) => {e.target.style.display='none'}} />
                    <h1 className="pf-brand">PassFlow Ai</h1>
                    <div className="success-icon">??/div>
                    <h2>鍮꾨?踰덊샇 ?ㅼ젙 ?꾨즺!</h2>
                    <p>異뺥븯?⑸땲?? 愿由ъ옄 怨꾩젙??鍮꾨?踰덊샇媛 ?깃났?곸쑝濡??ㅼ젙?섏뿀?듬땲??</p>
                    <button className="primary-btn" onClick={() => navigate('/login')}>吏湲?諛붾줈 濡쒓렇?명븯湲?/button>
                </div>
            </div>
        );
    }

    return (
        <div className="auth-action-container">
            <div className="auth-card">
                {/* Fallback to text if logo image is missing during loading */}
                <div className="pf-header">
                    <img src="/logo192.png" alt="PassFlow Logo" className="pf-logo" onError={(e) => {e.target.style.display='none'}} />
                    <h1 className="pf-brand">PassFlow Ai</h1>
                </div>

                <h2>愿由ъ옄 鍮꾨?踰덊샇 ?ㅼ젙</h2>
                <p className="subtitle">
                    ?섏쁺?⑸땲??<br/>
                    <span className="email-highlight">{email}</span> 怨꾩젙??br/>?덈줈??鍮꾨?踰덊샇瑜??ㅼ젙?댁＜?몄슂.
                </p>

                <form onSubmit={handleSubmit} className="auth-form">
                    <div className="form-group">
                        <label>??鍮꾨?踰덊샇 (6???댁긽)</label>
                        <input 
                            type="password" 
                            placeholder="?덉쟾??鍮꾨?踰덊샇 ?낅젰"
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label>鍮꾨?踰덊샇 ?뺤씤</label>
                        <input 
                            type="password" 
                            placeholder="鍮꾨?踰덊샇 ?ㅼ떆 ?낅젰"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            required
                        />
                    </div>

                    <button type="submit" className="primary-btn submit-btn" disabled={isSubmitting}>
                        {isSubmitting ? '?ㅼ젙 以?..' : '鍮꾨?踰덊샇 ???諛??꾨즺'}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default AuthActionPage;

import { useState, useEffect, useRef, useCallback } from 'react';
import { signInAnonymously } from 'firebase/auth';
import { auth } from '../firebase';
import { storageService } from '../services/storage';
import { getKSTHour, getDaysRemaining, safeParseDate } from '../utils/dates';
import { isMemberActive } from '../utils/adminCalculations';

import { getStaticStandbyMessage } from '../utils/aiStandbyHelper';
import { AIMessages } from '../constants/aiMessages';
import { CHECKIN_CONFIG } from '../constants/CheckInConfig';
import { extractFaceDescriptor } from '../services/facialService';
import { memberService } from '../services/memberService';

// Hooks
import { useAlwaysOnGuardian } from '../hooks/useAlwaysOnGuardian';
import { useAttendanceCamera } from '../hooks/useAttendanceCamera';
import { useNetworkMonitor } from '../hooks/useNetworkMonitor';
import { useTTS } from '../hooks/useTTS';
import { useFacialRecognition } from '../hooks/useFacialRecognition';
import { useKioskNotice } from '../hooks/useKioskNotice';
import { useProximityReturn } from '../hooks/useProximityReturn';

import { usePWA } from '../hooks/usePWA';
import { useStudioConfig } from '../contexts/StudioContext';

// Components (Ultra-Modular)
import TopBar from '../components/checkin/TopBar';
import { getHolidayName } from '../utils/holidays';
import { subscribeMonthlyClasses } from '../services/scheduleService';
import { STUDIO_CONFIG } from '../studioConfig';
import CheckInInfoSection from '../components/checkin/CheckInInfoSection';
import CheckInKeypadSection from '../components/checkin/CheckInKeypadSection';
import MessageOverlay from '../components/checkin/MessageOverlay';
import SelectionModal from '../components/checkin/SelectionModal';
import DuplicateConfirmModal from '../components/checkin/DuplicateConfirmModal';
import InstructorQRModal from '../components/InstructorQRModal';
import KioskInstallGuideModal from '../components/checkin/KioskInstallGuideModal';
import FaceRegistrationModal from '../components/checkin/FaceRegistrationModal';

const CheckInPage = () => {
    const { config } = useStudioConfig();
    const logoWide = config.ASSETS?.LOGO?.WIDE || '/assets/passflow_logo.png';
    const rys200Logo = config.ASSETS?.LOGO?.RYS200 || '/assets/RYS200.webp';
    const branches = config.BRANCHES || [];
    // [FIX] FACE_RECOGNITION_ENABLED留뚯쑝濡??쇨뎬 ?몄떇 ?쒖꽦??(SHOW_CAMERA_PREVIEW???꾨━酉??쒖떆留??쒖뼱)
    const faceRecognitionEnabled = config.POLICIES?.FACE_RECOGNITION_ENABLED === true;

    const getBgForPeriod = (p) => {
        const bgKey = p.toUpperCase();
        return config.ASSETS?.BACKGROUNDS?.[bgKey] || config.ASSETS?.BACKGROUNDS?.NIGHT;
    };

    // States
    const [pin, setPin] = useState('');
    const [message, setMessage] = useState(null);
    const [loading, setLoading] = useState(false);
    const [isReady, setIsReady] = useState(false);
    const [currentBranch, setCurrentBranch] = useState(() => {
        const saved = storageService.getKioskBranch();
        if (saved) return saved;
        if (branches.length === 1) {
            storageService.setKioskBranch(branches[0].id);
            return branches[0].id;
        }
        return null;
    });
    const [duplicateMembers, setDuplicateMembers] = useState([]);
    const [showSelectionModal, setShowSelectionModal] = useState(false);
    const [weather, setWeather] = useState(null);
    const [aiExperience, setAiExperience] = useState(null);
    const [aiEnhancedMsg, setAiEnhancedMsg] = useState(null);
    const [aiLoading, setAiLoading] = useState(false);
    const [showInstructorQR, setShowInstructorQR] = useState(false);
    const [keypadLocked, setKeypadLocked] = useState(false);
    const [showFaceRegModal, setShowFaceRegModal] = useState(false);
    const [showDuplicateConfirm, setShowDuplicateConfirm] = useState(false);
    const [showKioskInstallGuide, setShowKioskInstallGuide] = useState(false);
    const [pendingPin, setPendingPin] = useState(null);
    const [duplicateTimer, setDuplicateTimer] = useState(config.POLICIES?.SESSION_AUTO_CLOSE_SEC || 25);
    const [isDuplicateFlow, setIsDuplicateFlow] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState('異쒖꽍 ?뺤씤 以?..');
    const [period, setPeriod] = useState(() => {
        const h = getKSTHour();
        if (h >= 6 && h < 12) return 'morning';
        if (h >= 12 && h < 17) return 'afternoon';
        if (h >= 17 && h < 21) return 'evening';
        return 'night';
    });
    const [bgImage, setBgImage] = useState(null);
    const [monthlyClasses, setMonthlyClasses] = useState({});
    const [isOnline, setIsOnline] = useState(true);

    // Refs
    const timerRef = useRef(null);
    const duplicateAutoCloseRef = useRef(null);
    const recentCheckInsRef = useRef([]);
    const autoUpdateRef = useRef({ isIdle: true, pin: '' });
    const pinRef = useRef(pin);
    const warmupTriggered = useRef(false);

    // Custom Hooks
    const pwaContext = usePWA();
    const { checkConnection } = useNetworkMonitor();
    const { speak } = useTTS();
    const photoEnabled = config.POLICIES?.PHOTO_ENABLED === true || faceRecognitionEnabled === true;
    const { videoRef, canvasRef, capturePhoto, uploadPhoto, stream: cameraStream } = useAttendanceCamera(photoEnabled);

    const {
        faceModelsLoaded, isScanning, faceVideoRef,
        lastDescriptorRef, activeTaskIdRef, findBestMatch
    } = useFacialRecognition({
        enabled: faceRecognitionEnabled,
        autoUpdateRef,
        attendanceVideoRef: videoRef, // ?ъ쭊 罹≪쿂??移대찓??怨듭쑀
        proceedWithCheckIn: useCallback((pin, isDup, memberId, task) => {
            proceedWithCheckIn(pin, isDup, memberId, task);
        }, []),
    });

    const { kioskSettings, kioskNoticeHidden, setKioskNoticeHidden } = useKioskNotice({
        isReady, currentBranch, message, showSelectionModal, showDuplicateConfirm
    });

    // 洹쇱젒 媛먯?: 怨듭? ?붾㈃ ?쒖떆 以?+ ?듭뀡 ON?대㈃ 移대찓?쇰줈 ?쇨뎬 媛먯? ???먮룞 ?꾪솚
    const isNoticeVisible = !!(kioskSettings?.active && kioskSettings?.imageUrl && !kioskNoticeHidden && !message);
    useProximityReturn({
        enabled: !!kioskSettings?.proximityReturn,
        isNoticeVisible,
        videoRef: faceVideoRef,
        onPersonDetected: useCallback(() => setKioskNoticeHidden(true), [setKioskNoticeHidden])
    });

    const language = CHECKIN_CONFIG.LOCALE;
    const qrCodeUrl = `${CHECKIN_CONFIG.ASSETS.QR_CODE_BASE_URL}?${CHECKIN_CONFIG.ASSETS.QR_CODE_PARAMS}&data=${encodeURIComponent(window.location.origin + '/member')}`;

    const warmupFunctions = useCallback(() => {
        if (warmupTriggered.current) return;
        warmupTriggered.current = true;
        import('firebase/functions').then(({ httpsCallable }) => {
             import('../firebase').then(({ functions }) => {
                 const checkInCall = httpsCallable(functions, 'checkInMemberV2Call');
                 checkInCall({ ping: true }).catch(() => {});
                 const loginCall = httpsCallable(functions, 'memberLoginV2Call');
                 loginCall({ ping: true }).catch(() => {});
             }).catch(() => {});
        }).catch(() => {});
    }, []);

    // ?? Effects ??
    useEffect(() => { 
        // [洹쇰낯 ?섏젙] ?ㅼ삤?ㅽ겕媛 ?좏쑕 ?곹깭?몄? ?섎굹??boolean?쇰줈 ?듯빀 ?먮떒
        // ?대뼡 紐⑤떖/?ㅻ쾭?덉씠/濡쒕뵫?대뱺 ?섎굹?쇰룄 ?쒖꽦?대㈃ isIdle = false
        const isIdle = !message && !loading && !showSelectionModal && !showDuplicateConfirm 
            && !showFaceRegModal && !showInstructorQR && !showKioskInstallGuide;
        autoUpdateRef.current = { isIdle, pin };
        pinRef.current = pin;
    }, [pin, message, loading, showSelectionModal, showDuplicateConfirm, showFaceRegModal, showInstructorQR, showKioskInstallGuide]);

    useEffect(() => {
        const init = async () => {
            try { await signInAnonymously(auth); } catch (e) {}
            await storageService.initialize({ mode: 'kiosk' });
            setIsReady(true);
            fetchWeatherAndAI();
        };
        init();
        const vh = () => document.documentElement.style.setProperty('--vh', `${window.innerHeight * 0.01}px`);
        vh(); window.addEventListener('resize', vh);

        let unsubClasses = () => {};
        if (currentBranch) {
            const todayCurrent = new Date();
            unsubClasses = subscribeMonthlyClasses(
                currentBranch, todayCurrent.getFullYear(), todayCurrent.getMonth() + 1,
                (data) => setMonthlyClasses(data || {})
            );
        }

        return () => { unsubClasses(); window.removeEventListener('resize', vh); };
    }, []);

    // [PWA] ?ㅼ삤?ㅽ겕 ???덊솕硫??ㅼ튂 ?좊룄 ?먮룞 ?앹뾽 - ?쒓굅 (?곗튂 ?덊빐??媛묒옄湲??⑤뒗 踰꾧렇 ?먯씤)
    useEffect(() => {
        // ?먮룞 ?앹뾽???쒓굅?섏뿬 ?붾㈃??諛⑺빐?섏? ?딅룄濡???(QR 肄붾뱶 ?대┃ ?쒖뿉留??섎룞?쇰줈 ??
    }, [isReady, pwaContext.isStandalone]);

    useEffect(() => { setBgImage(getBgForPeriod(period)); }, [period]);

    // ?? Business Logic ??
    const loadAIExperience = async (name = "諛⑸Ц ?뚯썝", credits = null, days = null, w = null) => {
        const isStandby = name === "諛⑸Ц ?뚯썝";
        try {
            const h = getKSTHour();
            if (h < CHECKIN_CONFIG.SERVICE_HOURS.AI_READY_START || h >= CHECKIN_CONFIG.SERVICE_HOURS.AI_READY_END) {
                setAiExperience({ message: AIMessages.FALLBACK_MESSAGE_OUTSIDE_BUSINESS_HOURS, isFallback: true });
                return;
            }
            const info = await storageService.getCurrentClass(currentBranch);
            const title = info?.title || "?먯쑉?섎젴";
            if (isStandby) {
                const staticMsg = getStaticStandbyMessage(h, w?.weathercode || '0', title);
                setAiExperience({ message: staticMsg, isFallback: true });
                setAiLoading(true);
                storageService.getAIExperience(name, 0, '?ㅻ뒛', h, title, w, null, null, language, null, 'visitor', 'checkin')
                    .then(res => { if (res?.message && !res.isFallback) setAiEnhancedMsg(res.message.replace(/?섎쭏?ㅽ뀒[.]?\s*?솋?/gi, '').trim()); })
                    .finally(() => setAiLoading(false));
            } else {
                const exp = await storageService.getAIExperience(name, 0, '?ㅻ뒛', h, title, w, credits, days, language, null, 'member', 'checkin');
                if (exp) setAiExperience({ ...exp, message: exp.message.replace(/?섎쭏?ㅽ뀒[.]?\s*?솋?/gi, '').trim() });
            }
        } catch (e) {}
    };

    const fetchWeatherAndAI = async () => {
        try {
            const r = await fetch('https://api.open-meteo.com/v1/forecast?latitude=37.5665&longitude=126.9780&current_weather=true');
            const d = await r.json();
            setWeather(d.current_weather);
            loadAIExperience("諛⑸Ц ?뚯썝", null, null, d.current_weather);
        } catch (e) { loadAIExperience(); }
    };

    const handleModalClose = useCallback((action) => {
        setKeypadLocked(true);
        action();
        setPin('');
        setAiEnhancedMsg(null);
        setAiLoading(false);
        setTimeout(() => setKeypadLocked(false), 350);
    }, []);

    const showCheckInSuccess = async (res, isDup = false) => {
        const m = res.member;
        const credits = m.credits ?? 0;
        let daysLeft = 999;
        if (m.endDate) {
            const end = safeParseDate(m.endDate);
            const now = new Date(); now.setHours(0,0,0,0); end.setHours(0,0,0,0);
            daysLeft = Math.ceil((end - now) / 86400000);
        }

        let msg = "?ㅻ뒛???섎젴???쒖옉?⑸땲??";
        let isConsecutive = false;
        let isExtra = false;

        if (res.isDuplicate) {
            isExtra = true;
        } else if (res.sessionCount && res.sessionCount > 1) {
            isExtra = isDup;
            isConsecutive = !isDup;
        }

        if (isExtra) { msg = "諛섍??뚯슂! ?대? 異쒖꽍 ?뺤씤???꾨즺?섏뿀?듬땲?? (異붽? 異쒖꽍)"; speak("success_extra"); }
        else if (isConsecutive) { msg = "?ㅻ뒛????踰덉㎏ ?섎젴???쒖옉?⑸땲?? (?곌컯 異쒖꽍)"; speak("success_consecutive"); }
        else if (daysLeft < 0) { msg = "?섎젴沅?湲곌컙??留뚮즺?섏뿀?듬땲?? ?좎깮?섍퍡???덈궡瑜??꾩??쒕┫寃뚯슂."; speak("denied"); }
        else if (credits < 0) { msg = "?섎젴 ?잛닔媛 紐⑤몢 ?뚯쭊?섏뿀?듬땲?? ?좎깮?섍퍡???덈궡瑜??꾩??쒕┫寃뚯슂."; speak("denied"); }
        else if (credits === 0 || daysLeft === 0) { msg = "?ㅻ뒛???대쾲 ?섎젴沅뚯쓽 留덉?留??좎씠?ㅼ슂. ?뺤꽦 媛?앺븳 ?섎젴 ?섏꽭??"; speak("last_session"); }
        else { speak("success"); }

        await new Promise(r => setTimeout(r, 100));
        setMessage({ type: 'success', member: m, text: `${m.name}??, subText: msg });
        if (timerRef.current) clearTimeout(timerRef.current);
        timerRef.current = setTimeout(() => handleModalClose(() => setMessage(null)), CHECKIN_CONFIG.TIMEOUTS.SUCCESS_MODAL);
        setAiEnhancedMsg("?ㅻ뒛???됱삩???붽? ?덈궡???쒕┫寃뚯슂. ?섎쭏?ㅽ뀒 ?솋");
        setAiLoading(false);
    };

    const proceedWithCheckIn = async (p, isDup = false, memberIdToForce = null, facialTask = null) => {
        setLoading(true);
        recentCheckInsRef.current.push({ pin: p, timestamp: Date.now() });
        try {
            if (facialTask && !lastDescriptorRef.current) {
                try {
                    const timeout = new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), 1500));
                    await Promise.race([facialTask, timeout]);
                } catch (e) {}
            }

            let targetMemberId = memberIdToForce;
            let isFacialMatch = false;

            if (!targetMemberId) {
                let members = [];
                try { members = await storageService.findMembersByPhone(p); }
                catch (lookupErr) { members = []; }

                if (members.length === 0) {
                    speak("error");
                    await new Promise(r => setTimeout(r, 300));
                    setMessage({ type: 'error', text: '?뚯썝 ?뺣낫瑜?李얠쓣 ???놁뒿?덈떎.' });
                    return;
                }
                if (members.length > 1) {
                    // [FIX] 鍮꾪솢???뚯썝 ?쒖쇅 (?섍컯沅?留뚮즺/?잛닔 ?뚯쭊)
                    const activeMembers = members.filter(m => isMemberActive(m));
