                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    zIndex: 1
                }}
            />

            <div style={{
                position: 'relative',
                zIndex: 10,
                width: '100%',
                maxWidth: '400px',
                padding: '40px',
                backgroundColor: 'rgba(20, 20, 20, 0.9)',
                borderRadius: '24px',
                border: `1px solid ${primaryColor}33`,
                boxShadow: `0 20px 50px ${primaryColor}33`,
                textAlign: 'center',
            }}>
                <div className="login-header" style={{ textAlign: 'center', marginBottom: '4vh' }}>
                {logoUrl ? (
                    <img src={logoUrl} alt={studioName} style={{ width: '220px', marginBottom: '2vh', filter: `drop-shadow(0 0 10px ${primaryColor}4D)` }} />
                ) : (
                    <h2 style={{ color: 'white', marginBottom: '2vh' }}>{studioName}</h2>
                )}
                <h1 style={{ fontSize: '1.8rem', fontWeight: 'bold', color: primaryColor, marginBottom: '1vh', letterSpacing: '-0.02em' }}>{config.IDENTITY?.SLOGAN || ''}</h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1rem', opacity: 0.8 }}>{studioName} 愿由ъ옄 ?쒖뒪??/p>
            </div>

                {error && (
                    <div style={{
                        backgroundColor: 'rgba(255, 69, 58, 0.15)',
                        color: '#FF6B6B',
                        padding: '12px',
                        borderRadius: '12px',
                        marginBottom: '20px',
                        fontSize: '0.9rem',
                        border: '1px solid rgba(255, 69, 58, 0.3)'
                    }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
                    <div style={{ textAlign: 'left' }}>
                        <label style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.5)', marginLeft: '12px', marginBottom: '5px', display: 'block' }}>?대찓??/label>
                        <input
                            type="email"
                            placeholder="example@test.com"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            style={{
                                width: '100%',
                                padding: '14px',
                                borderRadius: '12px',
