                                backgroundColor: 'rgba(255,255,255,0.05)',
                                color: 'white',
                                fontSize: '1rem',
                                outline: 'none'
                            }}
                            required
                        />
                    </div>
                    <div style={{ textAlign: 'left' }}>
                        <label style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.5)', marginLeft: '12px', marginBottom: '5px', display: 'block' }}>鍮꾨?踰덊샇</label>
                        <input
                            type="password"
                            placeholder="?™™™™™™™?

submit"
                        disabled={loading}
                        style={{
                            width: '100%',
                            padding: '16px',
                            borderRadius: '12px',
                            border: 'none',
                            backgroundColor: 'var(--primary-gold)',
                            color: 'var(--text-on-primary)',
                            fontSize: '1rem',
                            fontWeight: 'bold',
                            cursor: loading ? 'not-allowed' : 'pointer',
                            marginTop: '10px',
                            transition: 'transform 0.2s',
                            boxShadow: '0 4px 15px rgba(var(--primary-rgb), 0.4)'
                        }}
                    >
                        {loading ? '?몄쬆 以?..' : '?묒냽?섍린'}
                    </button>
                    
                    {/* SaaS Admin Demo Quick Login Button */}
                    {typeof window !== 'undefined' && window.location.hostname.includes('passflow-demo') && (
                        <button
                            type="button"
                            onClick={(e) => {
                                e.preventDefault();
                                setEmail('demo@passflow.kr');
                                setPassword('passflowdemo!');
                                setTimeout(() => {
                                    // Trigger form submission manually or via state change
                                    const mockEvent = { preventDefault: () => {} };
                                    handleLogin(mockEvent);
                                }, 100);
                            }}
                            disabled={loading}
                            style={{
                                width: '100%',
                                padding: '16px',
                                borderRadius: '12px',
                                border: '1px solid rgba(212, 175, 55, 0.4)',
                                backgroundColor: 'rgba(212, 175, 55, 0.15)',
                                color: 'var(--primary-gold)',
                                fontSize: '1rem',
                                fontWeight: 'bold',
                                cursor: loading ? 'not-allowed' : 'pointer',
                                marginTop: '4px',
                                transition: 'transform 0.2s',
                            }}
                        >
                            ?? 愿由ъ옄 ?곕え ?먮룞 濡쒓렇??r
                        </button>
                    )}
                </form>
            </div>
            <p style={{ position: 'relative', zIndex: 10, marginTop: '30px', color: 'rgba(255,255,255,0.3)', fontSize: '0.8rem' }}>
                짤 {new Date().getFullYear()} {studioName}. All rights reserved.
            </p>
        </div>
    );
};

export default LoginPage;

import { useState, useEffect, useRef, useCallback } from 'react';
